cat /data/data/com.termux/files/home/projects/earth-0/sessions/2026-06-12T05-39-29-344Z_019eba57-afbc-710d-9847-063ce994e639.jsonl | python3 -c "
import json, sys
for line in sys.stdin:
    d = json.loads(line)
    if d['type'] == 'message':
        m = d.get('message', {})
        role = m.get('role', '?')
        content = m.get('content', [])
        for c in content:
            if c.get('type') == 'text':
                print(f'[{role}]: {c[\"text\"][:200]}')
" 2>/dev/null || cat /data/data/com.termux/files/home/projects/earth-0/sessions/2026-06-12T05-39-29-344Z_019eba57-afbc-710d-9847-063ce994e639.jsonl | grep -o '"text":"[^"]*"' | head -20
